-- Full Korea location catalog (시/도 already seeded; fill 시군구 + 동읍면)
-- Generated by database/scripts/build-kr-locations.mjs
-- Source: HangJeongDong administrative boundaries (행정동)

CREATE TEMP TABLE _kr_cities (
  state_code VARCHAR(40) NOT NULL,
  code VARCHAR(40) NOT NULL,
  name_ko TEXT NOT NULL,
  name_en TEXT NOT NULL,
  lat DECIMAL(10,7),
  lng DECIMAL(10,7)
) ON COMMIT DROP;

CREATE TEMP TABLE _kr_districts (
  state_code VARCHAR(40) NOT NULL,
  city_code VARCHAR(40) NOT NULL,
  code VARCHAR(40) NOT NULL,
  name_ko TEXT NOT NULL,
  name_en TEXT NOT NULL,
  lat DECIMAL(10,7),
  lng DECIMAL(10,7)
) ON COMMIT DROP;








































-- Remap existing KR cities that match by Korean name onto official sgg codes
UPDATE location_cities lc
SET
  code = seed.code,
  name = jsonb_build_object('ko', seed.name_ko, 'en', seed.name_en),
  latitude = seed.lat,
  longitude = seed.lng,
  is_active = TRUE,
  updated_at = NOW()
FROM _kr_cities seed
JOIN location_states st ON st.country_code = 'KR' AND st.code = seed.state_code
WHERE lc.state_id = st.id
  AND lc.name->>'ko' = seed.name_ko
  AND lc.code IS DISTINCT FROM seed.code;

-- Also remap known legacy slug codes (046/047 samples) if name match missed
UPDATE location_cities lc
SET
  code = seed.code,
  name = jsonb_build_object('ko', seed.name_ko, 'en', seed.name_en),
  latitude = seed.lat,
  longitude = seed.lng,
  is_active = TRUE,
  updated_at = NOW()
FROM _kr_cities seed
JOIN location_states st ON st.country_code = 'KR' AND st.code = seed.state_code
JOIN (VALUES
  ('seoul', 'gangnam', '강남구'),
  ('seoul', 'gangseo', '강서구'),
  ('seoul', 'mapo', '마포구'),
  ('seoul', 'songpa', '송파구'),
  ('seoul', 'nowon', '노원구'),
  ('seoul', 'yongsan', '용산구'),
  ('seoul', 'jongno', '종로구'),
  ('seoul', 'jung', '중구'),
  ('gyeonggi', 'suwon', '수원시 영통구'),
  ('gyeonggi', 'seongnam', '성남시 분당구'),
  ('busan', 'haeundae', '해운대구'),
  ('busan', 'busanjin', '부산진구'),
  ('incheon', 'yeonsu', '연수구'),
  ('gyeonggi', 'goyang', '고양시 일산동구'),
  ('gyeonggi', 'bucheon', '부천시'),
  ('gyeonggi', 'yongin', '용인시 수지구')
) AS legacy(state_code, old_code, name_ko)
  ON legacy.state_code = seed.state_code AND legacy.name_ko = seed.name_ko
WHERE lc.state_id = st.id
  AND lc.code = legacy.old_code;

-- Insert missing KR cities
SELECT st.id,
       seed.code,
       jsonb_build_object('ko', seed.name_ko, 'en', seed.name_en),
       seed.lat,
       seed.lng,
       TRUE,
       1000
FROM _kr_cities seed
JOIN location_states st ON st.country_code = 'KR' AND st.code = seed.state_code
WHERE NOT EXISTS (
  SELECT 1 FROM location_cities lc
  WHERE lc.state_id = st.id AND (lc.code = seed.code OR lc.name->>'ko' = seed.name_ko)
);

-- Refresh names/coords for all matched KR cities
UPDATE location_cities lc
SET
  name = jsonb_build_object('ko', seed.name_ko, 'en', seed.name_en),
  latitude = seed.lat,
  longitude = seed.lng,
  is_active = TRUE,
  updated_at = NOW()
FROM _kr_cities seed
JOIN location_states st ON st.country_code = 'KR' AND st.code = seed.state_code
WHERE lc.state_id = st.id
  AND (lc.code = seed.code OR lc.name->>'ko' = seed.name_ko);

-- Hide legacy sample cities that are not in the official 시군구 catalog
UPDATE location_cities lc
SET is_active = FALSE, updated_at = NOW()
FROM location_states st
WHERE lc.state_id = st.id
  AND st.country_code = 'KR'
  AND NOT EXISTS (
    SELECT 1 FROM _kr_cities seed
    WHERE seed.state_code = st.code
      AND (seed.code = lc.code OR seed.name_ko = lc.name->>'ko')
  );

-- Replace KR districts with full 행정동 catalog (FK ON DELETE SET NULL on user refs)
DELETE FROM location_districts d
USING location_cities c
JOIN location_states st ON st.id = c.state_id
WHERE d.city_id = c.id AND st.country_code = 'KR';

SELECT c.id,
       seed.code,
       jsonb_build_object('ko', seed.name_ko, 'en', seed.name_en),
       seed.lat,
       seed.lng,
       TRUE,
       1000
FROM _kr_districts seed
JOIN location_states st ON st.country_code = 'KR' AND st.code = seed.state_code
JOIN location_cities c ON c.state_id = st.id AND c.code = seed.city_code;

